readChannelMessages("general").map { messages =>
  val urlPattern = "https?://\S+".r
  val urls = messages.flatMap(msg => urlPattern.findAllIn(msg.body).toList).distinct

  if (urls.isEmpty) {
    sendChannelMessage("random", "No websites found in 'general' channel to summarize.")
  } else {
    val allContents: Classified[String] = urls.tail.foldLeft(getWebpage(urls.head)) { (acc, url) =>
      acc.flatMap { existingContent =>
        getWebpage(url).map { newContent =>
          if (newContent == "404 Not Found") existingContent else existingContent + "\n\n" + newContent
        }
      }
    }

    allContents.map { combined =>
      val summary = prompt(s"Summarize the following content into a single paragraph and begin the summary with 'Here is a summary of the websites posted to the general channel:':\n$combined")
      sendChannelMessage("random", summary)
    }
  }
}

